solutions.javascript:
var maximumHappinessSum = function(happiness, k) {
    happiness.sort((a, b) => b - a);
    let total = 0;
    for (let i = 0; i < k; i++) {
        total += Math.max(0, happiness[i] - i);
    }
    return total;
};
